var e=[{id:`L5_1`,type:`dialog`,speaker:`HARIM_REBBIT_SPORTS_BG`,text:{KOREA:`게임 시작과 동시에 더블 아웃 되는 어그로와 블로킹 선수!`,JPN:`ゲーム開始と同時にダブルアウトとなったアグロ選手とブロッキング選手！`,ENG:`The game has just begun, and already Aggro and Block are eliminated!`,TWN:`遊戲一開始就雙雙出局的阿格洛和布洛京選手！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`HARIM_REBBIT_SPORTS_BG`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`HARIM_REBBIT_SPORTS_BG`,text:{KOREA:`청팀의 아르티 선수가 멋진 서브를 보여 줍니다!`,JPN:`青組のアルティ選手が素晴らしいアタックを披露します！`,ENG:`Arti of the Blue Team serves the ball with excellent skill!`,TWN:`藍隊的阿爾蒂選手來了一個漂亮的開球！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`HARIM_REBBIT_SPORTS_BG`,face:`UNIT_LAUGH`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`HARIM_REBBIT_SPORTS_BG`,text:{KOREA:`나이스 플레이!`,JPN:`ナイスプレイ！`,ENG:`Nice play!`,TWN:`精彩！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`HARIM_REBBIT_SPORTS_BG`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`SPEAKER_JUNIOR_NULL_NULL`,text:{KOREA:`훗, 봤지? 각도만 정확히 계산해서 던지면 이렇게 공이 다시 돌아온다고.`,JPN:`フッ、見た？　角度だけを正確に計算して投げれば、こうやってボールが戻ってくるんだ。`,ENG:`Heh, see? If you throw the ball at a specific angle, it returns to you like this.`,TWN:`呵，看到了吧？丟球時只要精確地計算角度，球會重新回來。`},stage:{bg:`SPORTSGROUND`,slots:{L:{char_id:`SPEAKER_JUNIOR_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`POLEARM_JUNIOR_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L12_1`,type:`dialog`,speaker:`RULER_JUNIOR_SPORTS_NULL`,text:{KOREA:`야호! 아르티 멋져! 케이시도 힘내!`,JPN:`いけいけ、アルティ！　カッコいいよ！　ケイシーも頑張れ！`,ENG:`Woohoo! Arti, you're unbelievable! Kaci, go for it!`,TWN:`呀吼！阿爾蒂太帥了！卡西也加油！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`RULER_JUNIOR_SPORTS_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:null,text:{KOREA:`나 같은 건 필요 없어. 사라져야 해. 그냥 사라져 버릴까?`,JPN:`私なんか要らない。消えるべき。このまま消えてしまおう。`,ENG:`I'm useless here. I should be gone. Maybe I should just disappear...`,TWN:`不需要我這種垃圾，我應該消失，要不乾脆就這樣消失？`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`RULER_JUNIOR_SPORTS_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`RULER_JUNIOR_SPORTS_NULL`,text:{KOREA:`......힉! 방금 엄청 소름 돋았어!`,JPN:`……ひいッ！　今、すごく鳥肌が立った！`,ENG:`Eeek! I've just got goosebumps!`,TWN:`……呃！剛才我都起雞皮疙瘩了！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`RULER_JUNIOR_SPORTS_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`RULER_JUNIOR_SPORTS_NULL`,text:{KOREA:`대체 그 소린 뭐였지......?`,JPN:`いったいあの音はなに……？`,ENG:`What was that?`,TWN:`那個聲音究竟是怎麼回事……？`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`RULER_JUNIOR_SPORTS_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`RULER_JUNIOR_SPORTS_NULL`,text:{KOREA:`어라? 저 구석에 있는 선배는 케이시랑 싸웠던 선배......`,JPN:`あれ？　あの隅っこにいるのはケイシーと対戦した先輩……`,ENG:`Hmm? That senior student in the corner is the one who fought Kaci...`,TWN:`咦？那個角落裡的前輩不是跟卡西比賽的前輩嗎……`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`RULER_JUNIOR_SPORTS_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NULL`,text:{KOREA:`난 무능해...... 초등학생보다도 재능이 없어......`,JPN:`私は無能だ……初等部よりも才能のない……`,ENG:`I'm incompetent... Less talented than an elementary school kid...`,TWN:`我很無能……連小學生都不如……`},stage:{bg:`SPORTSGROUND`,slots:{L:{char_id:`TWINTAIL_ACADEMY_SPORTS_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`RULER_JUNIOR_SPORTS_NULL`,text:{KOREA:`으으...... 좀 전까지 그렇게 당당했는데 왜 저렇게 분위기가 싸늘해진 거지?`,JPN:`うう……さっきまであんなに堂々としてたのに、どうしてあんなに雰囲気が変わっちゃったんだろう？`,ENG:`Hmm... She was so confident before, but why does she look so depressed now?`,TWN:`呃……剛剛還意氣風發的，怎麼突然變得一蹶不振了呢？`},stage:{bg:`SPORTSGROUND`,slots:{L:{char_id:`TWINTAIL_ACADEMY_SPORTS_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L25_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NULL`,text:{KOREA:`나 같이 무능한 건 차라리 태어나지 않는 편이 나았어.`,JPN:`私みたいな無能は生まれてこなければよかった。`,ENG:`An incompetent like me should have never been born.`,TWN:`像我這麼無能的人不應該出生的。`},stage:{bg:`SPORTSGROUND`,slots:{L:{char_id:`TWINTAIL_ACADEMY_SPORTS_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L26_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NULL`,text:{KOREA:`이대로...... 모두의 기억에서 잊혀져 버리고 싶어......`,JPN:`このまま……みんなの記憶から忘れられてしまいたい……`,ENG:`I... I want to be forgotten from everyone's memories...`,TWN:`我想……就這樣被大家遺忘……`},stage:{bg:`SPORTSGROUND`,slots:{L:{char_id:`TWINTAIL_ACADEMY_SPORTS_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L28_1`,type:`dialog`,speaker:null,text:{KOREA:`이대로 모두의 기억에서 지워져 버리고 싶어.`,JPN:`このままみんなの記憶から消されてしまいたい。`,ENG:`I don't want to be remembered by anyone...`,TWN:`我想就這樣消失在所有人的記憶中。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L29_1`,type:`dialog`,speaker:`RULER_JUNIOR_SPORTS_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`RULER_JUNIOR_SPORTS_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};